const {
  withInfoPlist,
  withDangerousMod,
  withXcodeProject,
} = require('expo/config-plugins');
const fs = require('fs');
const path = require('path');

const SSL_FILENAME = 'SaiSSL.m';

const SSL_CODE = `\
//
//  SaiSSL.m — Auto-generated by allow-http Expo config plugin.
//  Trusts self-signed certificates for all React Native HTTP requests.
//
//  RCTHTTPRequestHandler already implements URLSession:didReceiveChallenge:,
//  so a category cannot override it. We swizzle the existing method instead.
//

#import <Foundation/Foundation.h>
#import <objc/runtime.h>
#import <React/RCTBridgeModule.h>
#import <React/RCTHTTPRequestHandler.h>

// ---- Native module: prevents linker dead-code stripping ----

@interface SaiSSL : NSObject <RCTBridgeModule>
@end

// Separate bootstrap class so we can use +load (RCT_EXPORT_MODULE on SaiSSL
// generates its own +load and would conflict). This guarantees the swizzle
// fires regardless of whether SaiSSL is ever instantiated by the RN bridge
// (relevant for TurboModules / new-arch lazy module init).
@interface SaiSSLBootstrap : NSObject
@end

@implementation SaiSSLBootstrap
+ (void)load {
    extern void SaiSSL_install(void);
    SaiSSL_install();
    dispatch_async(dispatch_get_main_queue(), ^{ SaiSSL_install(); });
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)),
                   dispatch_get_main_queue(), ^{ SaiSSL_install(); });
}
@end

@implementation SaiSSL

RCT_EXPORT_MODULE();

+ (BOOL)requiresMainQueueSetup {
    return NO;
}

// React.framework is dynamic — RCTHTTPRequestHandler isn't registered yet at
// dyld constructor time. We can't use +load here because RCT_EXPORT_MODULE
// already defines one. +initialize is called by the objc runtime the first
// time this class is messaged; RN's module registry instantiates SaiSSL at
// bridge startup, which happens after React.framework has loaded — so by then
// RCTHTTPRequestHandler is registered and reachable.
+ (void)initialize {
    if (self != [SaiSSL class]) return;
    extern void SaiSSL_install(void);
    SaiSSL_install();
    dispatch_async(dispatch_get_main_queue(), ^{ SaiSSL_install(); });
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)),
                   dispatch_get_main_queue(), ^{ SaiSSL_install(); });
}

@end

// ---- Swizzled replacement for the session-level SSL challenge handler ----

static void SaiSSL_acceptTrust(NSURLAuthenticationChallenge *challenge,
    void (^completionHandler)(NSURLSessionAuthChallengeDisposition,
                              NSURLCredential * _Nullable))
{
    SecTrustRef serverTrust = challenge.protectionSpace.serverTrust;

    // Extract the server certificate and set it as a trusted anchor.
    // This forces SecTrust to evaluate against our explicit anchor list
    // instead of the system root store, bypassing ATS rejection.
    CFIndex certCount = SecTrustGetCertificateCount(serverTrust);
    NSMutableArray *certs = [NSMutableArray arrayWithCapacity:certCount];
    for (CFIndex i = 0; i < certCount; i++) {
        SecCertificateRef cert = SecTrustGetCertificateAtIndex(serverTrust, i);
        if (cert) [certs addObject:(__bridge id)cert];
    }
    if (certs.count > 0) {
        SecTrustSetAnchorCertificates(serverTrust, (__bridge CFArrayRef)certs);
        SecTrustSetAnchorCertificatesOnly(serverTrust, NO);
    }

    // Evaluate trust — we don't care about the result, we accept regardless
    CFErrorRef evalError = NULL;
    bool trusted = SecTrustEvaluateWithError(serverTrust, &evalError);
    NSLog(@"[SaiSSL] trust eval: %s (error: %@)",
          trusted ? "trusted" : "untrusted",
          evalError ? (__bridge NSError *)evalError : nil);
    if (evalError) CFRelease(evalError);

    NSURLCredential *credential =
        [NSURLCredential credentialForTrust:serverTrust];
    completionHandler(NSURLSessionAuthChallengeUseCredential, credential);
}

static void SaiSSL_didReceiveChallenge(id self, SEL _cmd,
    NSURLSession *session,
    NSURLAuthenticationChallenge *challenge,
    void (^completionHandler)(NSURLSessionAuthChallengeDisposition,
                              NSURLCredential * _Nullable))
{
    NSLog(@"[SaiSSL] session challenge: host=%@ method=%@",
          challenge.protectionSpace.host,
          challenge.protectionSpace.authenticationMethod);

    if ([challenge.protectionSpace.authenticationMethod
            isEqualToString:NSURLAuthenticationMethodServerTrust]) {
        SaiSSL_acceptTrust(challenge, completionHandler);
    } else {
        completionHandler(NSURLSessionAuthChallengePerformDefaultHandling, nil);
    }
}

// Also handle the per-task variant
static void SaiSSL_task_didReceiveChallenge(id self, SEL _cmd,
    NSURLSession *session,
    NSURLSessionTask *task,
    NSURLAuthenticationChallenge *challenge,
    void (^completionHandler)(NSURLSessionAuthChallengeDisposition,
                              NSURLCredential * _Nullable))
{
    NSLog(@"[SaiSSL] task challenge: host=%@ method=%@",
          challenge.protectionSpace.host,
          challenge.protectionSpace.authenticationMethod);

    if ([challenge.protectionSpace.authenticationMethod
            isEqualToString:NSURLAuthenticationMethodServerTrust]) {
        SaiSSL_acceptTrust(challenge, completionHandler);
    } else {
        completionHandler(NSURLSessionAuthChallengePerformDefaultHandling, nil);
    }
}

void SaiSSL_install(void) {
    NSLog(@"[SaiSSL] SSL trust override loaded — swizzling RCTHTTPRequestHandler");

    Class cls = objc_getClass("RCTHTTPRequestHandler");
    if (!cls) {
        NSLog(@"[SaiSSL] ERROR: RCTHTTPRequestHandler class not found");
        return;
    }

    // Swizzle session-level challenge
    SEL sessionSel = @selector(URLSession:didReceiveChallenge:completionHandler:);
    Method sessionMethod = class_getInstanceMethod(cls, sessionSel);
    if (sessionMethod) {
        method_setImplementation(sessionMethod, (IMP)SaiSSL_didReceiveChallenge);
        NSLog(@"[SaiSSL] swizzled URLSession:didReceiveChallenge:completionHandler:");
    } else {
        // Method doesn't exist yet — add it.
        // Signature: void(self, _cmd, NSURLSession*, NSURLAuthenticationChallenge*, void(^)(...))
        const char *types = "v@:@@@?";
        class_addMethod(cls, sessionSel, (IMP)SaiSSL_didReceiveChallenge, types);
        NSLog(@"[SaiSSL] added URLSession:didReceiveChallenge:completionHandler:");
    }

    // Swizzle per-task challenge
    SEL taskSel = @selector(URLSession:task:didReceiveChallenge:completionHandler:);
    Method taskMethod = class_getInstanceMethod(cls, taskSel);
    if (taskMethod) {
        method_setImplementation(taskMethod, (IMP)SaiSSL_task_didReceiveChallenge);
        NSLog(@"[SaiSSL] swizzled URLSession:task:didReceiveChallenge:completionHandler:");
    } else {
        // Signature: void(self, _cmd, NSURLSession*, NSURLSessionTask*, NSURLAuthenticationChallenge*, void(^)(...))
        const char *types = "v@:@@@@?";
        class_addMethod(cls, taskSel, (IMP)SaiSSL_task_didReceiveChallenge, types);
        NSLog(@"[SaiSSL] added URLSession:task:didReceiveChallenge:completionHandler:");
    }
}
`;

function withSSLFile(config) {
  return withDangerousMod(config, [
    'ios',
    (mod) => {
      const iosRoot = mod.modRequest.platformProjectRoot;
      const targetName = mod.modRequest.projectName;
      const targetDir = path.join(iosRoot, targetName);
      fs.mkdirSync(targetDir, { recursive: true });

      fs.writeFileSync(path.join(targetDir, SSL_FILENAME), SSL_CODE, 'utf-8');

      return mod;
    },
  ]);
}

function withSSLXcodeRef(config) {
  return withXcodeProject(config, (mod) => {
    const proj = mod.modResults;
    const targetName = mod.modRequest.projectName;
    const targetPath = `${targetName}/${SSL_FILENAME}`;

    const existing = proj.pbxFileReferenceSection
      ? Object.values(proj.pbxFileReferenceSection()).find(
          (ref) => ref && ref.path === SSL_FILENAME
        )
      : null;

    if (!existing) {
      const groupKey = proj.findPBXGroupKey({ name: targetName });
      proj.addSourceFile(targetPath, null, groupKey);
    }

    // Force linker to keep all Objective-C categories (prevents dead-code stripping)
    const configs = proj.pbxXCBuildConfigurationSection();
    for (const key in configs) {
      const cfg = configs[key];
      if (cfg && cfg.buildSettings) {
        const flags = cfg.buildSettings.OTHER_LDFLAGS;
        if (Array.isArray(flags)) {
          if (!flags.includes('"-ObjC"')) {
            flags.push('"-ObjC"');
          }
        } else if (typeof flags === 'string') {
          if (!flags.includes('-ObjC')) {
            cfg.buildSettings.OTHER_LDFLAGS = [flags, '"-ObjC"'];
          }
        } else {
          cfg.buildSettings.OTHER_LDFLAGS = ['"$(inherited)"', '"-ObjC"'];
        }
      }
    }

    return mod;
  });
}

module.exports = function allowHttp(config) {
  config = withInfoPlist(config, (mod) => {
    mod.modResults.NSAppTransportSecurity = {
      NSAllowsArbitraryLoads: true,
      NSAllowsLocalNetworking: true,
      // iOS 26 ignores NSAllowsArbitraryLoads for NSURLSession; explicit
      // exception domains are required to permit plain HTTP from fetch().
      NSExceptionDomains: {
        // Tailscale MagicDNS — covers *.ts.net hostnames
        'ts.net': {
          NSExceptionAllowsInsecureHTTPLoads: true,
          NSIncludesSubdomains: true,
        },
        // Direct IP access (loopback for simulator, LAN for local dev)
        '127.0.0.1': {
          NSExceptionAllowsInsecureHTTPLoads: true,
        },
        'localhost': {
          NSExceptionAllowsInsecureHTTPLoads: true,
        },
      },
    };
    mod.modResults.NSLocalNetworkUsageDescription =
      'SAI needs local network access to communicate with your desktop over Tailscale.';
    mod.modResults.NSBonjourServices = ['_sai._tcp'];
    return mod;
  });

  config = withSSLFile(config);
  config = withSSLXcodeRef(config);

  return config;
};
